 21: impl TaskBoardSections {
 22:     pub fn entries_for_status_mut(&mut self, status: TaskBoardStatus) -> &mut Vec<TaskBoardEntry> {
 23:         match status {
 24:             TaskBoardStatus::Unknown => &mut self.stub,
 25:             TaskBoardStatus::Ready => &mut self.ready,
 26:             TaskBoardStatus::InProgress => &mut self.in_progress,
 27:             TaskBoardStatus::Blocked => &mut self.blocked,
 28:             TaskBoardStatus::Gated => &mut self.gated,
 29:             TaskBoardStatus::Done => &mut self.done,
 30:             TaskBoardStatus::Cancelled => &mut self.cancelled,
 31:         }
 32:     }
