 34:     pub fn entries_for_status(&self, status: TaskBoardStatus) -> &Vec<TaskBoardEntry> {
 35:         match status {
 36:             TaskBoardStatus::Unknown => &self.stub,
 37:             TaskBoardStatus::Ready => &self.ready,
 38:             TaskBoardStatus::InProgress => &self.in_progress,
 39:             TaskBoardStatus::Blocked => &self.blocked,
 40:             TaskBoardStatus::Gated => &self.gated,
 41:             TaskBoardStatus::Done => &self.done,
 42:             TaskBoardStatus::Cancelled => &self.cancelled,
