 47: fn status_for_heading(heading: &str) -> Option<TaskBoardStatus> {
 48:     let heading = heading.trim();
 49:     let heading = heading.strip_prefix("## ")?;
 50:     let title = heading.trim();
 51: 
 52:     if title.eq_ignore_ascii_case("Ready for Dev") {
 53:         return Some(TaskBoardStatus::Ready);
 54:     }
 55:     if title.eq_ignore_ascii_case("In Progress") {
 56:         return Some(TaskBoardStatus::InProgress);
 57:     }
 58:     if title.eq_ignore_ascii_case("Blocked") {
 59:         return Some(TaskBoardStatus::Blocked);
 60:     }
 61:     if title.eq_ignore_ascii_case("Done") {
 62:         return Some(TaskBoardStatus::Done);
 63:     }
 64:     if title.to_ascii_lowercase().starts_with("stub backlog") {
 65:         return Some(TaskBoardStatus::Unknown);
 66:     }
 67:     if title.to_ascii_lowercase().starts_with("superseded") {
 68:         return Some(TaskBoardStatus::Cancelled);
 69:     }
 70: 
 71:     None
 72: }
 73: 
 74: fn parse_entry_line(line: &str) -> Option<(String, String)> {
 75:     let line = line.trim();
 76:     if !line.starts_with("- **[") {
 77:         return None;
 78:     }
 79:     let after_prefix = line.strip_prefix("- **[")?;
 80:     let (wp_id, rest) = after_prefix.split_once("]**")?;
 81:     let rest = rest.trim_start();
 82:     let rest = rest.strip_prefix("-")?.trim_start();
 83:     let token_part = rest.strip_prefix("[")?;
 84:     let (token, _rest) = token_part.split_once(']')?;
 85:     Some((wp_id.trim().to_string(), token.trim().to_string()))
 86: }
 87: 
 88: pub fn parse_task_board(markdown: &str) -> TaskBoardSections {
 89:     let mut sections = TaskBoardSections::default();
 90:     let mut current: Option<TaskBoardStatus> = None;
 91: 
 92:     for raw_line in markdown.lines() {
 93:         let line = raw_line.trim_end();
 94:         if let Some(status) = status_for_heading(line) {
 95:             current = Some(status);
 96:             continue;
 97:         }
 98: 
 99:         let Some(status) = current else { continue };
100:         let Some((wp_id, token)) = parse_entry_line(line) else {
101:             continue;
102:         };
103: 
104:         sections
105:             .entries_for_status_mut(status)
106:             .push(TaskBoardEntry {
107:                 wp_id,
108:                 token,
109:                 status,
110:             });
111:     }
112: 
113:     sections
114: }
115: 
116: fn format_entry(entry: &TaskBoardEntry) -> String {
117:     format!("- **[{}]** - [{}]", entry.wp_id, entry.token)
118: }
