120: #[derive(Debug, Clone, Copy)]
121: struct SectionWindow {
122:     status: TaskBoardStatus,
123:     start: usize,
124: }
125: 
126: fn find_section_windows(lines: &[String]) -> Vec<SectionWindow> {
127:     let mut headings: Vec<(usize, TaskBoardStatus)> = Vec::new();
128:     for (idx, line) in lines.iter().enumerate() {
129:         if let Some(status) = status_for_heading(line) {
130:             headings.push((idx, status));
131:         }
132:     }
133: 
134:     let mut windows: Vec<SectionWindow> = Vec::new();
135:     for (start, status) in headings {
136:         windows.push(SectionWindow { status, start });
137:     }
138:     windows
139: }
140: 
141: pub fn rewrite_task_board(markdown: &str, canonical: &TaskBoardSections) -> String {
142:     let mut lines: Vec<String> = markdown.lines().map(|l| l.to_string()).collect();
143: 
144:     let mut windows = find_section_windows(&lines);
145:     windows.sort_by(|a, b| b.start.cmp(&a.start));
146: 
147:     for window in windows {
148:         let mut end = lines.len();
149:         for i in (window.start + 1)..lines.len() {
150:             if lines[i].trim_start().starts_with("## ") {
151:                 end = i;
152:                 break;
153:             }
154:         }
155: 
156:         let mut entries: Vec<TaskBoardEntry> = canonical
157:             .entries_for_status(window.status)
158:             .iter()
159:             .cloned()
160:             .collect();
161:         entries.sort_by(|a, b| a.wp_id.cmp(&b.wp_id).then_with(|| a.token.cmp(&b.token)));
162:         let mut new_lines: Vec<String> = entries.iter().map(format_entry).collect();
163: 
164:         let mut insert_at = end;
165:         for i in (window.start + 1)..end {
166:             if parse_entry_line(&lines[i]).is_some() {
167:                 insert_at = i;
168:                 break;
169:             }
170:         }
171: 
172:         let mut i = window.start + 1;
173:         while i < end && i < lines.len() {
174:             if lines[i].trim_start().starts_with("## ") {
175:                 break;
176:             }
177:             if parse_entry_line(&lines[i]).is_some() {
178:                 lines.remove(i);
179:                 end = end.saturating_sub(1);
180:                 if i < insert_at {
181:                     insert_at = insert_at.saturating_sub(1);
182:                 }
183:                 continue;
184:             }
185:             i += 1;
186:         }
187: 
188:         if !new_lines.is_empty() && insert_at == end {
189:             if insert_at > 0 && !lines[insert_at.saturating_sub(1)].trim().is_empty() {
190:                 new_lines.insert(0, String::new());
191:             }
192:         }
193: 
194:         lines.splice(insert_at..insert_at, new_lines);
195:     }
196: 
197:     let mut out = lines.join("\n");
198:     if !out.ends_with('\n') {
199:         out.push('\n');
200:     }
201:     out
202: }

