   21: 
   22: impl RuntimeGovernancePaths {
   23:     pub fn resolve() -> Result<Self, io::Error> {
   24:         let workspace_root = resolve_workspace_root()
   25:             .map_err(|err| io::Error::new(io::ErrorKind::Other, err.to_string()))?;
   26:         let configured = std::env::var(RUNTIME_GOVERNANCE_ROOT_ENV)
   27:             .ok()
   28:             .map(|value| value.trim().to_string())
   29:             .filter(|value| !value.is_empty())
   30:             .map(PathBuf::from);
   31:         Self::from_workspace_root_with_override(workspace_root, configured)
   32:     }
   33: 
   34:     pub fn from_workspace_root(workspace_root: PathBuf) -> Result<Self, io::Error> {
   35:         Self::from_workspace_root_with_override(workspace_root, None)
   36:     }
   37: 
   38:     fn from_workspace_root_with_override(
   39:         workspace_root: PathBuf,
   40:         override_root: Option<PathBuf>,
   41:     ) -> Result<Self, io::Error> {
   42:         let workspace_root = absolutize(workspace_root)?;
   43:         let configured =
   44:             override_root.unwrap_or_else(|| PathBuf::from(RUNTIME_GOVERNANCE_DEFAULT_ROOT));
   45:         if has_parent_dir(&configured) {
   46:             return Err(io::Error::new(
   47:                 io::ErrorKind::InvalidInput,
   48:                 "runtime governance root must not contain '..' segments",
   49:             ));
   50:         }
   51: 
   52:         let governance_root = if configured.is_absolute() {
   53:             configured
   54:         } else {
   55:             workspace_root.join(configured)
   56:         };
   57:         let governance_root = absolutize(governance_root)?;
   58: 
   59:         ensure_runtime_boundary(&workspace_root, &governance_root)?;
   60: 
   61:         Ok(Self {
   62:             workspace_root,
   63:             governance_root,
   64:         })
   65:     }
