 1: #!/usr/bin/env node
 2: /**
 3:  * Helper: docs-only skeleton checkpoint commit for a WP [CX-GATE-001, CX-625]
 4:  *
 5:  * Enforces:
 6:  * - Only `.GOV/task_packets/{WP_ID}.md` is modified/staged/untracked.
 7:  * - Creates a commit: "docs: skeleton checkpoint [WP-{ID}]"
 8:  *
 9:  * This is the interface-first checkpoint required before implementation [CX-GATE-001].
10:  */
11: 
12: import fs from 'node:fs';
13: import path from 'node:path';
14: import { execSync } from 'node:child_process';
15: 
16: const wpId = process.argv[2];
17: if (!wpId) {
18:   console.error('Usage: node .GOV/scripts/validation/coder-skeleton-checkpoint.mjs WP-{ID}');
19:   process.exit(1);
20: }
21: 
22: const packetRel = path.join('.GOV', 'task_packets', `${wpId}.md`);
23: if (!fs.existsSync(packetRel)) {
24:   console.error(`FAIL: Task packet not found: ${packetRel}`);
25:   process.exit(1);
26: }
27: 
28: function git(args) {
29:   return execSync(`git ${args}`, { encoding: 'utf8' });
30: }
31: 
32: const checkpointSubject = `docs: skeleton checkpoint [${wpId}]`;
33: 
34: function latestCheckpointSha() {
35:   const log = git('log -n 50 --format=%H%x09%s');
36:   for (const line of log.split(/\r?\n/)) {
37:     if (!line) continue;
38:     const [sha, subject] = line.split('\t');
39:     if ((subject || '').trim() === checkpointSubject) {
40:       return (sha || '').trim();
41:     }
42:   }
43:   return '';
44: }
45: 
46: const currentBranch = git('rev-parse --abbrev-ref HEAD').trim();
47: 
48: // Refuse obvious wrong contexts.
49: if (currentBranch === 'main' || currentBranch.startsWith('role_') || currentBranch.startsWith('user_')) {
50:   console.error(`FAIL: Refusing to create a WP skeleton commit on branch "${currentBranch}".`);
51:   console.error(`Expected a WP feature branch for ${wpId}.`);
52:   process.exit(1);
53: }
54: 
55: const status = git('status --porcelain=v1');
56: const lines = status.split(/\r?\n/).filter(Boolean);
57: 
58: // Collect paths (including untracked) and enforce docs-only.
59: const changed = lines
60:   .map((line) => (line.length > 3 ? line.slice(3).trim() : ""))
61:   .filter(Boolean);
62: 
63: const allowed = new Set([packetRel.replace(/\\/g, '/')]);
64: const bad = changed.filter((p) => !allowed.has(p.replace(/\\/g, '/')));
65: 
66: if (bad.length > 0) {
67:   console.error('FAIL: Skeleton checkpoint must be docs-only.');
68:   console.error(`Allowed: ${packetRel.replace(/\\/g, '/')}`);
69:   console.error('Found additional changed/untracked paths:');
70:   bad.forEach((p) => console.error(`- ${p}`));
71:   process.exit(1);
72: }
73: 
74: if (changed.length === 0) {
75:   const checkpointSha = latestCheckpointSha();
76:   if (checkpointSha) {
77:     console.log(`PASS: Skeleton checkpoint already exists at ${checkpointSha}. Nothing new to commit.`);
78:     process.exit(0);
79:   }
80:   console.error(`FAIL: No changes detected. Edit ${packetRel.replace(/\\/g, '/')} (## SKELETON), then re-run.`);
81:   process.exit(1);
82: }
83: 
84: // Stage and commit.
85: execSync(`git add ${packetRel}`, { stdio: 'inherit' });
86: execSync(`git commit -m \"${checkpointSubject}\"`, { stdio: 'inherit' });
